1	const scaleRowHorizontally = (row: string, scaleFactor: number): string =>
2	  row.split("").map((char) => char.repeat(scaleFactor)).join("");
3	
4	const scaleImageVertically = (image: string[], scaleFactor: number): string[] =>
5	  image.flatMap((row) => Array(scaleFactor).fill(row));
6	
7	export function scalePixelArt(image: string[], scaleFactor: number): string[] {
8	  const horizontallyScaled = image.map((row) =>
9	    scaleRowHorizontally(row, scaleFactor)
10	  );
11	  return scaleImageVertically(horizontallyScaled, scaleFactor);
12	}
